  1→import React, {useMemo, useState} from 'react';
  2→import {
  3→  FlatList,
  4→  Image,
  5→  Pressable,
  6→  ScrollView,
  7→  StyleSheet,
  8→  Text,
  9→  View,
 10→} from 'react-native';
 11→import {useQuery, useMutation} from '@tanstack/react-query';
 12→import {BottomTabScreenProps} from '@react-navigation/bottom-tabs';
 13→import {CompositeScreenProps} from '@react-navigation/native';
 14→import {NativeStackScreenProps} from '@react-navigation/native-stack';
 15→import {SafeAreaView} from 'react-native-safe-area-context';
 16→import {PostCard} from '../../components/PostCard/PostCard';
 17→import {PostCardSkeleton} from '../../components/SkeletonLoader';
 18→import {CommentModal} from '../../components/Comments';
 19→import {RepostModal} from '../../components/RepostModal';
 20→import {SearchInput} from '../../components/SearchInput';
 21→import {Chip} from '../../components/Chip';
 22→import {Avatar} from '../../components/Avatar';
 23→import {EmptyState} from '../../components/EmptyState';
 24→import {SearchIcon, FireIcon} from '../../components/icons';
 25→import {useAuth} from '../../features/auth/AuthProvider';
 26→import {useTheme} from '../../theme/ThemeProvider';
 27→import {fonts, typeScale} from '../../theme/typography';
 28→import {spacing, radii} from '../../theme/spacing';
 29→import {
 30→  mobileApi,
 31→  type JournalItem,
 32→} from '../../lib/api/mobileApi';
 33→import {socialApi} from '../../lib/api/socialApi';
 34→import {queryClient} from '../../lib/queryClient';
 35→import {useBookmarkMutation} from '../../hooks/useSocialMutations';
 36→import {
 37→  extractPlainText,
 38→  extractBannerImage,
 39→  resolveCount,
 40→  calculateReadingTime,
 41→} from '../../lib/utils/journalHelpers';
 42→import type {MainTabParamList, RootStackParamList} from '../../navigation/types';
 43→
 44→type Props = CompositeScreenProps<
 45→  BottomTabScreenProps<MainTabParamList, 'Explore'>,
 46→  NativeStackScreenProps<RootStackParamList>
 47→>;
 48→
 49→type Tab = 'all' | 'users' | 'posts';
 50→
 51→const getHotScore = (journal: JournalItem): number => {
 52→  if (typeof journal.hot_score === 'number') return journal.hot_score;
 53→  const likes = resolveCount(journal.like_count, journal.likes_count);
 54→  const comments = resolveCount(journal.comment_count, journal.comments_count);
 55→  const bookmarks = resolveCount(journal.bookmark_count);
 56→  return likes + comments * 2 + bookmarks * 3;
 57→};
 58→
 59→export function ExploreScreen({navigation}: Props) {
 60→  const {user, session} = useAuth();
 61→  const {colors} = useTheme();
 62→  const token = session?.access_token ?? '';
 63→  const [query, setQuery] = useState('');
 64→  const [activeTab, setActiveTab] = useState<Tab>('all');
 65→  const [commentModal, setCommentModal] = useState<{
 66→    postId: string;
 67→    receiverId?: string;
 68→    commentCount: number;
 69→  } | null>(null);
 70→  const [repostModal, setRepostModal] = useState<{
 71→    journalId: string;
 72→    title?: string;
 73→    authorName?: string;
 74→    authorAvatar?: string;
 75→  } | null>(null);
 76→  const normalizedQuery = useMemo(() => query.trim(), [query]);
 77→  const isSearching = normalizedQuery.length >= 2;
 78→
 79→  // --- Data fetching ---
 80→
 81→  const hottestQuery = useQuery({
 82→    queryKey: ['explore-hottest-monthly', user?.id],
 83→    queryFn: () => mobileApi.getHottestMonthly(5, user?.id),
 84→    staleTime: 5 * 60 * 1000,
 85→  });
 86→
 87→  const usersQuery = useQuery({
 88→    queryKey: ['search-users', normalizedQuery],
 89→    enabled: isSearching && activeTab !== 'posts',
 90→    queryFn: () => mobileApi.searchUsers(normalizedQuery, 10),
 91→  });
 92→
 93→  const journalsQuery = useQuery({
 94→    queryKey: ['search-journals', normalizedQuery],
 95→    enabled: isSearching && activeTab !== 'users',
 96→    queryFn: () => mobileApi.searchJournals(normalizedQuery, 10),
 97→  });
 98→
 99→  const users = usersQuery.data?.data ?? [];
100→  const journals = journalsQuery.data?.data ?? [];
101→  const hottestPosts = hottestQuery.data?.data ?? [];
102→  const heroPost = hottestPosts[0] ?? null;
103→  const runnerPosts = hottestPosts.slice(1);
104→
105→  // --- Interaction handlers ---
106→
107→  const reactionMutation = useMutation({
108→    mutationFn: async ({
109→      journalId,
110→      receiverId,
111→      reactionType,
112→    }: {
113→      journalId: string;
114→      receiverId: string;
115→      reactionType: string;
116→    }) => {
117→      if (!token) throw new Error('Please log in to react.');
118→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
119→    },
120→    onSettled: () => {
121→      queryClient.invalidateQueries({queryKey: ['explore-hottest-monthly']});
122→      queryClient.invalidateQueries({queryKey: ['search-journals']});
123→    },
124→  });
125→
126→  const bookmarkMutation = useBookmarkMutation(token, ['explore-hottest-monthly', user?.id]);
127→
128→  const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
129→    if (!token) return;
130→    reactionMutation.mutate({journalId, receiverId, reactionType});
131→  };
132→
133→  const handleBookmark = (journalId: string) => {
134→    bookmarkMutation.mutate(journalId);
135→  };
136→
137→  const handleComment = (journalId: string, receiverId?: string, commentCount?: number) => {
138→    setCommentModal({postId: journalId, receiverId, commentCount: commentCount ?? 0});
139→  };
140→
141→  const handleRepost = (journalId: string, title?: string, authorName?: string, authorAvatar?: string) => {
142→    setRepostModal({journalId, title, authorName, authorAvatar});
143→  };
144→
145→  const handleAuthorPress = (item: JournalItem) => {
146→    const authorId = item.users?.id ?? item.user_id;
147→    if (!authorId) return;
148→    if (authorId === user?.id) {
149→      navigation.navigate('Main' as any, {screen: 'Profile'});
150→    } else {
151→      navigation.navigate('VisitProfile', {
152→        userId: authorId,
153→        username: item.users?.username ?? undefined,
154→      });
155→    }
156→  };
157→
158→  // --- Render helpers ---
159→
160→  const renderPostCard = (item: JournalItem) => {
161→    const preview = extractPlainText(item.content).slice(0, 180);
162→    const likeCount = resolveCount(item.like_count, item.likes_count);
163→    const commentCount = resolveCount(item.comment_count, item.comments_count);
164→    const bookmarkCount = resolveCount(item.bookmark_count);
165→    const bannerImage = extractBannerImage(item.content, (item as any).images);
166→    const receiverId = item.user_id ?? item.users?.id ?? '';
167→    const readingTime = calculateReadingTime(extractPlainText(item.content));
168→    const isRepost = !!item.is_repost;
169→    const repostSource = isRepost ? item.repost_source : null;
170→    const repostSourcePreview = repostSource?.content
171→      ? extractPlainText(repostSource.content).slice(0, 180)
172→      : '';
173→
174→    return (
175→      <PostCard
176→        title={item.title || 'Untitled Post'}
177→        bodyPreview={preview || 'No preview text available.'}
178→        authorName={item.users?.name || 'Unknown author'}
179→        authorAvatar={item.users?.image_url}
180→        authorBadge={item.users?.badge as 'legend' | 'og' | undefined}
181→        bannerImage={bannerImage}
182→        postType={item.post_type ?? undefined}
183→        readingTime={readingTime}
184→        likeCount={likeCount}
185→        commentCount={commentCount}
186→        bookmarkCount={bookmarkCount}
187→        userReaction={item.user_reaction}
188→        isBookmarked={!!item.has_bookmarked}
189→        onReact={type => handleReact(item.id, receiverId, type)}
190→        onComment={() => handleComment(item.id, receiverId, commentCount)}
191→        onBookmark={() => handleBookmark(item.id)}
192→        onRepost={() =>
193→          handleRepost(
194→            item.id,
195→            item.title ?? undefined,
196→            item.users?.name ?? undefined,
197→            item.users?.image_url ?? undefined,
198→          )
199→        }
200→        onPress={() => navigation.navigate('PostDetail', {journalId: item.id})}
201→        onAuthorPress={() => handleAuthorPress(item)}
202→        isRepost={isRepost}
203→        repostCaption={item.repost_caption}
204→        repostSourceTitle={repostSource?.title}
205→        repostSourcePreview={repostSourcePreview}
206→        repostSourceAuthorName={repostSource?.users?.name}
207→        repostSourceAuthorAvatar={repostSource?.users?.image_url}
208→        onEmbeddedPress={
209→          repostSource
210→            ? () => navigation.navigate('PostDetail', {journalId: repostSource.id})
211→            : undefined
212→        }
213→      />
214→    );
215→  };
216→
217→  const renderRunnerRow = (item: JournalItem, rank: number) => {
218→    const hotScore = getHotScore(item);
219→    const bannerImage = extractBannerImage(item.content, (item as any).images);
220→
221→    return (
222→      <Pressable
223→        key={item.id}
224→        style={[styles.runnerRow, {borderBottomColor: colors.borderCard}]}
225→        onPress={() => navigation.navigate('PostDetail', {journalId: item.id})}>
226→        <Text
227→          style={[
228→            styles.runnerRank,
229→            {color: rank <= 3 ? '#d97706' : colors.textMuted},
230→          ]}>
231→          #{rank}
232→        </Text>
233→        {bannerImage ? (
234→          <Image source={{uri: bannerImage}} style={styles.runnerThumb} />
235→        ) : (
236→          <View
237→            style={[styles.runnerThumbPlaceholder, {backgroundColor: colors.bgCard}]}
238→          />
239→        )}
240→        <View style={styles.runnerInfo}>
241→          <Text
242→            style={[styles.runnerTitle, {color: colors.textPrimary}]}
243→            numberOfLines={2}>
244→            {item.title || 'Untitled Post'}
